    { q: "Перечислите виды медицинских изображений с помощью ИИ", a: ["Рентгеновские снимки, МРТ, УЗИ и другие изображения", "Только рентгеновские снимки", "Только снимки МРТ", "Только снимки УЗИ", "Только снимки с ультрафиолетового излучения"], c: 0 },
    { q: "Укажите год выпуска первой версии ОС Windows", a: ["1985", "1981", "1990", "1995", "2000"], c: 0 },
    { q: "Определите основное назначение операционной системы Windows", a: ["Управление аппаратным обеспечением и предоставление интерфейса для пользователей", "Обработка данных", "Упрощение программирования", "Защита от вирусов", "Создание веб-сайтов"], c: 0 }
